1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  const liveKeys = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
13	
14	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const k = cellKey(neighbor[0], neighbor[1]);
19	      const entry = neighborCounts.get(k);
20	      if (entry) entry.count += 1;
21	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
22	    }
23	  }
24	
25	  const survives = (key: string, count: number): boolean =>
26	    count === 3 || (count === 2 && liveKeys.has(key));
27	
28	  const next: Cell[] = [];
29	  for (const [k, { cell, count }] of neighborCounts) {
30	    if (survives(k, count)) next.push(cell);
31	  }
32	  return next;
33	}
