1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] becomes []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1),(1,1)] becomes []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: live cell with 2 live neighbors survives — middle of 3-in-a-row survives", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("Rule 3 Overpopulation: live cell with 4 live neighbors dies — plus-sign center (1,1) dies", () => {
19	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive — L-corner [(0,0),(1,0),(0,1)] yields (1,1)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(result).toContainEqual([1, 1]);
25	  });
26	  it("Block still life: [(0,0),(1,0),(0,1),(1,1)] remains unchanged", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
28	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
29	      new Set(["0,0", "1,0", "0,1", "1,1"]),
30	    );
31	  });
32	  it("Blinker oscillator vertical to horizontal: [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]", () => {
33	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
34	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
35	      new Set(["-1,1", "0,1", "1,1"]),
36	    );
37	  });
38	  it("Handles negative coordinates: blinker shifted to (-5,-5) oscillates correctly", () => {
39	    const result = nextGeneration([[-5, -6], [-5, -5], [-5, -4]]);
40	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
41	      new Set(["-6,-5", "-5,-5", "-4,-5"]),
42	    );
43	  });
